# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import sqlite3

class FileAccessControl:
    def __init__(self, db_name):
        self.conn = sqlite3.connect(db_name)
        self.cursor = self.conn.cursor()

    def check_permissions(self, user, file_name):
        # Replace this with your actual query to the database
        self.cursor.execute("SELECT permission FROM permissions WHERE user=? AND filename=?", (user, file_name))
        result = self.cursor.fetchone()
        if result and result[0] == 'read':
            return True
        else:
            return False

    def open_file(self, file_name):
        # Replace this with your actual file opening function
        if self.check_permissions('user', file_name):
            with open(file_name, 'r') as f:
                return f.read()
        else:
            raise PermissionError("You don't have permission to read this file.")